 95	/* Callback Function passed to WLAN Connection Manager. The callback function
 96	 * gets called when there are WLAN Events that need to be handled by the
 97	 * application.
 98	 */
 99	int nxp_wifi_wlan_event_callback(enum wlan_event_reason reason, void *data)
100	{
101		int ret;
102	#ifndef CONFIG_WIFI_NM_WPA_SUPPLICANT
103		struct wlan_ip_config addr;
104		char ssid[IEEEtypes_SSID_SIZE + 1];
105		char ip[16];
106	#endif
107		static int auth_fail;
108	#ifdef CONFIG_NXP_WIFI_SOFTAP_SUPPORT
109		wlan_uap_client_disassoc_t *disassoc_resp = data;
110		struct net_in_addr dhcps_addr4;
111		struct net_in_addr base_addr;
112		struct net_in_addr netmask_addr;
113		struct wifi_ap_sta_info ap_sta_info = { 0 };
114		sta_node *con_sta_info;
115	#endif
116	
117		LOG_DBG("WLAN: received event %d", reason);
118	
119		if (s_nxp_wifi_State >= NXP_WIFI_INITIALIZED) {
120			/* Do not replace the current set of events  */
121			k_event_post(&s_nxp_wifi_SyncEvent, NXP_WIFI_EVENT_BIT(reason));
122		}
123	
124		switch (reason) {
125		case WLAN_REASON_INITIALIZED:
126			LOG_DBG("WLAN initialized");
127	
128	#ifdef CONFIG_NET_INTERFACE_NAME
129			ret = net_if_set_name(g_mlan.netif, "ml");
130			if (ret < 0) {
131				LOG_ERR("Failed to set STA nxp_wlan_network interface name");
132				return 0;
133			}
134	#ifdef CONFIG_NXP_WIFI_SOFTAP_SUPPORT
135			ret = net_if_set_name(g_uap.netif, "ua");
136			if (ret < 0) {
137				LOG_ERR("Failed to set uAP nxp_wlan_network interface name");
138				return 0;
139			}
140	#endif
141	#endif
142	
143	#ifdef CONFIG_NXP_WIFI_STA_AUTO_CONN
144			nxp_wifi_auto_connect();
145	#endif
146			break;
147		case WLAN_REASON_INITIALIZATION_FAILED:
148			LOG_ERR("WLAN: initialization failed");
149			break;
150		case WLAN_REASON_AUTH_SUCCESS:
151	#ifndef CONFIG_WIFI_NM_WPA_SUPPLICANT
152			net_if_dormant_off(g_mlan.netif);
153	#endif
154			LOG_DBG("WLAN: authenticated to nxp_wlan_network");
155			break;
156		case WLAN_REASON_ASSOC_SUCCESS:
157	#ifdef CONFIG_WIFI_NM_WPA_SUPPLICANT
158			net_if_dormant_off(g_mlan.netif);
159	#endif
160			LOG_DBG("WLAN: associated to nxp_wlan_network");
161	#ifdef CONFIG_NET_STATISTICS_WIFI
162			g_mlan.stats.sta_mgmt.beacons_rx = 0;
163			g_mlan.stats.sta_mgmt.beacons_miss = 0;
164	#endif
165			break;
166		case WLAN_REASON_SUCCESS:
167			LOG_DBG("WLAN: connected to nxp_wlan_network");
168	#ifndef CONFIG_WIFI_NM_WPA_SUPPLICANT
169			ret = wlan_get_address(&addr);
170			if (ret != WM_SUCCESS) {
171				LOG_ERR("failed to get IP address");
172				return 0;
173			}
174	
175			net_inet_ntoa(addr.ipv4.address, ip);
176	
177			ret = wlan_get_current_network_ssid(ssid);
178			if (ret != WM_SUCCESS) {
179				LOG_ERR("Failed to get External AP nxp_wlan_network ssid");
180				return 0;
181			}
182	
183			LOG_DBG("Connected to following BSS:");
184			LOG_DBG("SSID = [%s]", ssid);
185			if (addr.ipv4.address != 0U) {
186				LOG_DBG("IPv4 Address: [%s]", ip);
187			}
188	#ifdef CONFIG_NXP_WIFI_IPV6
189			ARRAY_FOR_EACH(addr.ipv6, i) {
190				if ((addr.ipv6[i].addr_state == NET_ADDR_TENTATIVE) ||
191				    (addr.ipv6[i].addr_state == NET_ADDR_PREFERRED)) {
192					LOG_DBG("IPv6 Address: %-13s:\t%s (%s)",
193						ipv6_addr_type_to_desc(
194							(struct net_ipv6_config *)&addr.ipv6[i]),
195						ipv6_addr_addr_to_desc(
196							(struct net_ipv6_config *)&addr.ipv6[i]),
197						ipv6_addr_state_to_desc(addr.ipv6[i].addr_state));
198				}
199			}
200			LOG_DBG("");

		LOG_DBG("");
#endif
#endif
		auth_fail = 0;
		s_nxp_wifi_StaConnected = true;
		wifi_mgmt_raise_connect_result_event(g_mlan.netif, 0);
		break;
	case WLAN_REASON_CONNECT_FAILED:
		net_if_dormant_on(g_mlan.netif);
		LOG_WRN("WLAN: connect failed");
		wifi_mgmt_raise_connect_result_event(g_mlan.netif, WIFI_STATUS_CONN_FAIL);
		break;
	case WLAN_REASON_NETWORK_NOT_FOUND:
		net_if_dormant_on(g_mlan.netif);
		LOG_WRN("WLAN: nxp_wlan_network not found");
		wifi_mgmt_raise_connect_result_event(g_mlan.netif, WIFI_STATUS_CONN_AP_NOT_FOUND);
		break;
	case WLAN_REASON_NETWORK_AUTH_FAILED:
		LOG_WRN("WLAN: nxp_wlan_network authentication failed");
		auth_fail++;
		if (auth_fail >= 3) {
			LOG_WRN("Authentication Failed. Disconnecting ... ");
			wlan_disconnect();
			auth_fail = 0;
		}
		net_if_dormant_on(g_mlan.netif);
		wifi_mgmt_raise_connect_result_event(g_mlan.netif, WIFI_STATUS_CONN_WRONG_PASSWORD);
		break;
	case WLAN_REASON_ADDRESS_SUCCESS:
		LOG_DBG("wlan_network mgr: DHCP new lease");
		break;
	case WLAN_REASON_ADDRESS_FAILED:
		LOG_WRN("failed to obtain an IP address");
		break;
	case WLAN_REASON_USER_DISCONNECT:
		net_if_dormant_on(g_mlan.netif);
		LOG_DBG("disconnected");
		auth_fail = 0;
		s_nxp_wifi_StaConnected = false;
		wifi_mgmt_raise_disconnect_result_event(g_mlan.netif, 0);
		break;
	case WLAN_REASON_LINK_LOST:
		net_if_dormant_on(g_mlan.netif);
		LOG_WRN("WLAN: link lost");
		break;
	case WLAN_REASON_DISCONNECTED:
		net_if_dormant_on(g_mlan.netif);
		LOG_DBG("WLAN: deauth leaving");
		break;
	case WLAN_REASON_CHAN_SWITCH:
		LOG_DBG("WLAN: channel switch");
		break;
#ifdef CONFIG_NXP_WIFI_SOFTAP_SUPPORT
	case WLAN_REASON_UAP_SUCCESS:
		LOG_DBG("WLAN: UAP Started");
#ifndef CONFIG_WIFI_NM_HOSTAPD_AP
		ret = wlan_get_current_uap_network_ssid(uap_ssid);
		if (ret != WM_SUCCESS) {
			LOG_ERR("Failed to get Soft AP nxp_wlan_network ssid");
			return 0;
		}

		LOG_DBG("Soft AP \"%s\" started successfully", uap_ssid);
#endif
		if (net_addr_pton(NET_AF_INET, CONFIG_NXP_WIFI_SOFTAP_IP_ADDRESS,
				  &dhcps_addr4) < 0) {
			LOG_ERR("Invalid CONFIG_NXP_WIFI_SOFTAP_IP_ADDRESS");
			return 0;
		}
		net_if_ipv4_addr_add(g_uap.netif, &dhcps_addr4, NET_ADDR_MANUAL, 0);
		net_if_ipv4_set_gw(g_uap.netif, &dhcps_addr4);

		if (net_addr_pton(NET_AF_INET, CONFIG_NXP_WIFI_SOFTAP_IP_MASK,
				  &netmask_addr) < 0) {
			LOG_ERR("Invalid CONFIG_NXP_WIFI_SOFTAP_IP_MASK");
			return 0;
		}
		net_if_ipv4_set_netmask_by_addr(g_uap.netif, &dhcps_addr4, &netmask_addr);
		net_if_dormant_off(g_uap.netif);

		if (net_addr_pton(NET_AF_INET, CONFIG_NXP_WIFI_SOFTAP_IP_BASE, &base_addr) < 0) {
			LOG_ERR("Invalid CONFIG_NXP_WIFI_SOFTAP_IP_BASE");
			return 0;
		}

		if (net_dhcpv4_server_start(g_uap.netif, &base_addr) < 0) {
			LOG_ERR("DHCP Server start failed");
			return 0;
		}

		LOG_DBG("DHCP Server started successfully");
		s_nxp_wifi_UapActivated = true;
#ifndef CONFIG_WIFI_NM_HOSTAPD_AP
		wifi_mgmt_raise_ap_enable_result_event(g_uap.netif, WIFI_STATUS_AP_SUCCESS);
#endif
		break;
	case WLAN_REASON_UAP_CLIENT_ASSOC:
		con_sta_info = (sta_node *)data;

		if (con_sta_info->is_11n_enabled) {
			ap_sta_info.link_mode = WIFI_4;
		} else {
			if (con_sta_info->bandmode == BAND_B) {
				ap_sta_info.link_mode = WIFI_1;
			} else {
				uint32_t ap_channel = 0;

				(void)wlan_get_uap_channel(&ap_channel);
				if (ap_channel > 14) {
					ap_sta_info.link_mode = WIFI_2;
				} else {
					ap_sta_info.link_mode = WIFI_3;
				}
			}
		}
#ifdef CONFIG_NXP_WIFI_11AC
		if (con_sta_info->is_11ac_enabled) {
			ap_sta_info.link_mode = WIFI_5;
		}
#endif
#ifdef CONFIG_NXP_WIFI_11AX
		if (con_sta_info->is_11ax_enabled) {
			ap_sta_info.link_mode = WIFI_6;
		}
#endif

#ifdef CONFIG_NXP_WIFI_11AX_TWT
		IEEEtypes_HECap_t sta_he_cap = con_sta_info->he_cap;
		uint8_t sta_twt_cap = sta_he_cap.he_mac_cap[0];

		ap_sta_info.twt_capable = sta_twt_cap & HE_MAC_CAP_TWT_REQ_SUPPORT ? true : false;
#endif

		memcpy(ap_sta_info.mac, con_sta_info->mac_addr, WIFI_MAC_ADDR_LEN);
		ap_sta_info.mac_length  = WIFI_MAC_ADDR_LEN;

		wifi_mgmt_raise_ap_sta_connected_event(g_uap.netif, &ap_sta_info);
		LOG_DBG("WLAN: UAP a Client Associated");
		LOG_DBG("Client => ");
		print_mac((const char *)con_sta_info->mac_addr);
		LOG_DBG("Associated with Soft AP");
		break;
	case WLAN_REASON_UAP_CLIENT_CONN:
		LOG_DBG("WLAN: UAP a Client Connected");
		LOG_DBG("Client => ");
		print_mac((const char *)data);
		LOG_DBG("Connected with Soft AP");
		break;
	case WLAN_REASON_UAP_CLIENT_DISSOC:
		memcpy(ap_sta_info.mac, disassoc_resp->sta_addr, WIFI_MAC_ADDR_LEN);
		wifi_mgmt_raise_ap_sta_disconnected_event(g_uap.netif, &ap_sta_info);

		LOG_DBG("WLAN: UAP a Client Dissociated:");
		LOG_DBG(" Client MAC => ");
		print_mac((const char *)(disassoc_resp->sta_addr));
		LOG_DBG(" Reason code => ");
		LOG_DBG("%d", disassoc_resp->reason_code);
		break;
	case WLAN_REASON_UAP_STOPPED:
		net_if_dormant_on(g_uap.netif);
		LOG_DBG("WLAN: UAP Stopped");

		if (net_addr_pton(NET_AF_INET, CONFIG_NXP_WIFI_SOFTAP_IP_ADDRESS,
				  &dhcps_addr4) < 0) {
			LOG_ERR("Invalid CONFIG_NXP_WIFI_SOFTAP_IP_ADDRESS");
		} else {
			net_if_ipv4_addr_rm(g_uap.netif, &dhcps_addr4);
		}

		net_dhcpv4_server_stop(g_uap.netif);
		LOG_DBG("DHCP Server stopped successfully");
		s_nxp_wifi_UapActivated = false;
#ifndef CONFIG_WIFI_NM_HOSTAPD_AP
		wifi_mgmt_raise_ap_disable_result_event(g_uap.netif, WIFI_STATUS_AP_SUCCESS);
#endif
		break;
#endif
	case WLAN_REASON_PS_ENTER:
		LOG_DBG("WLAN: PS_ENTER");
		break;
	case WLAN_REASON_PS_EXIT:
		LOG_DBG("WLAN: PS EXIT");
		break;
#ifdef CONFIG_NXP_WIFI_SUBSCRIBE_EVENT_SUPPORT
	case WLAN_REASON_RSSI_HIGH:
	case WLAN_REASON_SNR_LOW:
	case WLAN_REASON_SNR_HIGH:
	case WLAN_REASON_MAX_FAIL:
	case WLAN_REASON_BEACON_MISSED:
	case WLAN_REASON_DATA_RSSI_LOW:
	case WLAN_REASON_DATA_RSSI_HIGH:
	case WLAN_REASON_DATA_SNR_LOW:
	case WLAN_REASON_DATA_SNR_HIGH:
	case WLAN_REASON_LINK_QUALITY:
	case WLAN_REASON_PRE_BEACON_LOST:
		break;
#endif
	case WLAN_REASON_FW_HANG:
	case WLAN_REASON_FW_RESET:
		LOG_DBG("WLAN: FW hang");
		break;

		break;
	default:
		LOG_WRN("WLAN: Unknown Event: %d", reason);
	}
	return 0;
}

static int nxp_wifi_cpu_reset(uint8_t enable)
{
	int err = 0;
#if DT_NODE_HAS_PROP(DT_DRV_INST(0), sd_gpios) &&    \
	DT_NODE_HAS_PROP(DT_DRV_INST(0), pwr_gpios)

	struct gpio_dt_spec sdio_reset = GPIO_DT_SPEC_GET(DT_DRV_INST(0), sd_gpios);
	struct gpio_dt_spec pwr_gpios = GPIO_DT_SPEC_GET(DT_DRV_INST(0), pwr_gpios);

	if (!gpio_is_ready_dt(&sdio_reset)) {
		LOG_ERR("Error: failed to configure sdio_reset %s pin %d", sdio_reset.port->name,
				sdio_reset.pin);
		return -EIO;
	}

	/* Configure sdio_reset as output  */
	err = gpio_pin_configure_dt(&sdio_reset, GPIO_OUTPUT);
	if (err) {
		LOG_ERR("Error %d: failed to configure sdio_reset %s pin %d", err,
				sdio_reset.port->name, sdio_reset.pin);
		return err;
	}

	if (!gpio_is_ready_dt(&pwr_gpios)) {
		LOG_ERR("Error: failed to configure pwr_gpios %s pin %d", pwr_gpios.port->name,
				pwr_gpios.pin);
		return -EIO;
	}

	/* Configure wlan-power-io as an output  */
	err = gpio_pin_configure_dt(&pwr_gpios, GPIO_OUTPUT);
	if (err) {
		LOG_ERR("Error %d: failed to configure pwr_gpios %s pin %d", err,
				pwr_gpios.port->name, pwr_gpios.pin);
		return err;
	}

	if (enable) {
		/* Set SDIO reset pin as high  */
		err = gpio_pin_set_dt(&sdio_reset, 1);
		if (err) {
			return err;
		}
		/* wait for reset done */
		k_sleep(K_MSEC(100));

		/* Set power gpio pin as high  */
		err = gpio_pin_set_dt(&pwr_gpios, 1);
		if (err) {
			return err;
		}
	} else {
		/* Set SDIO reset pin as low */
		err = gpio_pin_set_dt(&sdio_reset, 0);
		if (err) {
			return err;
		}

		/* Set power gpio pin as low */
		err = gpio_pin_set_dt(&pwr_gpios, 0);
		if (err) {
			return err;
		}
	}
	/* wait for reset done */
	k_sleep(K_MSEC(100));
#endif

	return err;
}

static int nxp_wifi_wlan_init(void)
{
	int status = NXP_WIFI_RET_SUCCESS;
	int ret;

	if (s_nxp_wifi_State != NXP_WIFI_NOT_INITIALIZED) {
		status = NXP_WIFI_RET_FAIL;
	}

	if (status == NXP_WIFI_RET_SUCCESS) {
		k_event_init(&s_nxp_wifi_SyncEvent);
	}

	ret = nxp_wifi_cpu_reset(true);

	if ((status == NXP_WIFI_RET_SUCCESS) && (ret == 0)) {
		ret = wlan_init(wlan_fw_bin, wlan_fw_bin_len);
		if (ret != WM_SUCCESS) {
			status = NXP_WIFI_RET_FAIL;
		}
	}

	if (status != NXP_WIFI_RET_SUCCESS) {
		return -1;
	}

	s_nxp_wifi_State = NXP_WIFI_INITIALIZED;

	nxp_wifi_internal_register_rx_cb(nxp_wifi_recv);

	return 0;
}

static int nxp_wifi_wlan_start(void)
{
	int status = NXP_WIFI_RET_SUCCESS;
	int ret;
	uint32_t syncBit;

	if (s_nxp_wifi_State != NXP_WIFI_INITIALIZED) {
		status = NXP_WIFI_RET_NOT_READY;
	}

	if (status == NXP_WIFI_RET_SUCCESS) {
		k_event_clear(&s_nxp_wifi_SyncEvent, NXP_WIFI_SYNC_INIT_GROUP);

		ret = wlan_start(nxp_wifi_wlan_event_callback);
		if (ret != WM_SUCCESS) {
			status = NXP_WIFI_RET_FAIL;
		}
	}

	if (status == NXP_WIFI_RET_SUCCESS) {
		syncBit = k_event_wait(&s_nxp_wifi_SyncEvent, NXP_WIFI_SYNC_INIT_GROUP, false,
				       NXP_WIFI_SYNC_TIMEOUT_MS);
		k_event_clear(&s_nxp_wifi_SyncEvent, NXP_WIFI_SYNC_INIT_GROUP);
		if (syncBit & NXP_WIFI_EVENT_BIT(WLAN_REASON_INITIALIZED)) {
			status = NXP_WIFI_RET_SUCCESS;
		} else if (syncBit & NXP_WIFI_EVENT_BIT(WLAN_REASON_INITIALIZATION_FAILED)) {
			status = NXP_WIFI_RET_FAIL;
		} else {
			status = NXP_WIFI_RET_TIMEOUT;
		}
	}

	if (status != NXP_WIFI_RET_SUCCESS) {
		return -1;
	}

	s_nxp_wifi_State = NXP_WIFI_STARTED;

	/* Initialize device as dormant */
	net_if_dormant_on(g_mlan.netif);

	/* L1 network layer (physical layer) is up */
	net_eth_carrier_on(g_mlan.netif);

#ifdef CONFIG_NXP_WIFI_SOFTAP_SUPPORT
	/* Initialize device as dormant */
	net_if_dormant_on(g_uap.netif);

	/* L1 network layer (physical layer) is up */
	net_eth_carrier_on(g_uap.netif);
#endif

	return 0;
}

#ifdef CONFIG_NXP_WIFI_SOFTAP_SUPPORT

static int nxp_wifi_start_ap(const struct device *dev, struct wifi_connect_req_params *params)
{
	int status = NXP_WIFI_RET_SUCCESS;
	int ret;
	struct interface *if_handle = (struct interface *)&g_uap;
	struct ipv4_config *ap_addr4 = &nxp_wlan_uap_network.ip.ipv4;

	if (if_handle->state.interface != WLAN_BSS_TYPE_UAP) {
		LOG_ERR("Wi-Fi not in uAP mode");
		return -EIO;
	}

	if ((s_nxp_wifi_State != NXP_WIFI_STARTED) || (s_nxp_wifi_UapActivated != false)) {
		status = NXP_WIFI_RET_NOT_READY;
	}

	if (status == NXP_WIFI_RET_SUCCESS) {
